declare global {
  // `@workspace/api-zod` is used in Node runtimes (api-server) where the DOM lib
  // isn't enabled in tsconfig. Orval's output references `File`/`Blob`.
  // These shims make the package compile in non-DOM TypeScript projects.
  // Runtime behavior depends on the environment (Node 20+ includes File/Blob).
  // eslint-disable-next-line no-var
  var File: any;
  // eslint-disable-next-line no-var
  var Blob: any;

  interface Blob {}
  interface File extends Blob {}
}

export {};

